import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const BlockMaster = () => {
    const [blocks, setBlocks] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [formData, setFormData] = useState({ department: '', programme: '', blockName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchBlocks();
        fetchDepartments();
    }, []);

    const fetchBlocks = async () => {
        try {
            const { data } = await API.get('/master/block');
            setBlocks(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching blocks' });
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching departments' });
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching programmes' });
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData({...formData, department: deptId, programme: ''});
        fetchProgrammes(deptId);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/block', formData);
            setFormData({ department: '', programme: '', blockName: '' });
            fetchBlocks();
            setMessage({ type: 'success', text: '✓ Block added successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error adding block' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>🏠 Block Master</h1>
                    <p style={styles.subtitle}>Manage all building blocks</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' 
                            ? 'rgba(16, 185, 129, 0.2)' 
                            : 'rgba(239, 68, 68, 0.2)',
                        borderColor: message.type === 'success' ? '#10b981' : '#ef4444',
                        color: message.type === 'success' ? '#a7f3d0' : '#fca5a5',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.container}>
                    <div style={styles.formSide}>
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Department</label>
                                <select 
                                    required
                                    value={formData.department}
                                    onChange={handleDepartmentChange}
                                    style={styles.input}
                                >
                                    <option value="">Select Department</option>
                                    {departments.map(dept => (
                                        <option key={dept._id} value={dept._id}>{dept.department}</option>
                                    ))}
                                </select>
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Programme</label>
                                <select 
                                    required
                                    value={formData.programme}
                                    onChange={e => setFormData({...formData, programme: e.target.value})}
                                    style={styles.input}
                                >
                                    <option value="">Select Programme</option>
                                    {programmes.map(prog => (
                                        <option key={prog._id} value={prog._id}>{prog.programme}</option>
                                    ))}
                                </select>
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>Block Name</label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.blockName}
                                    onChange={e => setFormData({...formData, blockName: e.target.value})}
                                    style={styles.input}
                                    placeholder="e.g., Block A, Block B..."
                                />
                            </div>

                            <button type="submit" disabled={loading} style={{...styles.button, opacity: loading ? 0.6 : 1}}>
                                {loading ? '⏳ Adding...' : '➕ Add Block'}
                            </button>
                        </form>
                    </div>

                    <div style={styles.tableSide}>
                        <h3 style={styles.tableTitle}>📋 Block List</h3>
                        <div style={styles.tableContainer}>
                            <table style={styles.table}>
                                <thead>
                                    <tr style={styles.tableHeaderRow}>
                                        <th style={{...styles.tableHeader, width: '33%'}}>Department</th>
                                        <th style={{...styles.tableHeader, width: '33%'}}>Programme</th>
                                        <th style={{...styles.tableHeader, width: '34%'}}>Block Name</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {blocks.length > 0 ? (
                                        blocks.map((block, idx) => (
                                            <tr key={block._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                <td style={styles.tableCell}>{block.department?.department}</td>
                                                <td style={styles.tableCell}>{block.programme?.programme}</td>
                                                <td style={{...styles.tableCell, textAlign: 'center'}}>
                                                    <span style={styles.badge}>{block.blockName}</span>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr>
                                            <td colSpan="3" style={{...styles.tableCell, textAlign: 'center', color: '#94a3b8'}}>
                                                No blocks found
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const styles = {
    pageWrapper: {
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
        color: '#e0e7ff',
        fontFamily: "'Poppins', sans-serif",
    },
    contentArea: {
        maxWidth: '1400px',
        margin: '0 auto',
        padding: '40px 30px',
    },
    headerSection: {
        marginBottom: '40px',
